import {
  GoogleGenAI,
  Video,
  VideoGenerationReferenceImage,
  VideoGenerationReferenceType,
} from '@google/genai';
import {GenerateVideoParams, GenerationMode, AspectRatio, ImageFile} from '../types';

export const enhancePrompt = async (prompt: string, role: 'artist' | 'director'): Promise<string> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const instruction = role === 'artist' 
    ? "You are a world-class prompt engineer for image generation. Take the user's basic idea and turn it into a detailed, cinematic, high-quality prompt. Focus on lighting, composition, style, and mood. Respond ONLY with the enhanced prompt text. Keep it under 100 words."
    : "You are a cinematic director. Given an initial scene and a user's vision for movement, create a technical prompt for a video AI. Describe camera movement (pan, tilt, zoom), character action, and visual progression. Focus on cinematic continuity. Respond ONLY with the enhanced prompt text. Keep it under 100 words.";

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `User Input: ${prompt}`,
    config: { systemInstruction: instruction }
  });

  return response.text || prompt;
};

export const generateImage = async (prompt: string, aspectRatio: AspectRatio): Promise<ImageFile> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: prompt,
    config: {
      imageConfig: {
        aspectRatio: aspectRatio === AspectRatio.LANDSCAPE ? "16:9" : "9:16"
      }
    }
  });

  const part = response.candidates[0].content.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("No image generated");

  const base64 = part.inlineData.data;
  const byteCharacters = atob(base64);
  const byteNumbers = new Array(byteCharacters.length);
  for (let i = 0; i < byteCharacters.length; i++) {
    byteNumbers[i] = byteCharacters.charCodeAt(i);
  }
  const byteArray = new Uint8Array(byteNumbers);
  const blob = new Blob([byteArray], {type: 'image/png'});
  const file = new File([blob], "generated_keyframe.png", {type: 'image/png'});

  return { file, base64 };
};

export const generateVideo = async (
  params: GenerateVideoParams,
): Promise<{objectUrl: string; blob: Blob; uri: string; video: Video}> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

  const config: any = {
    numberOfVideos: 1,
    resolution: params.resolution,
  };

  if (params.mode !== GenerationMode.EXTEND_VIDEO) {
    config.aspectRatio = params.aspectRatio;
  }

  const generateVideoPayload: any = {
    model: params.model,
    config: config,
    prompt: params.prompt,
  };

  if (params.startFrame) {
    generateVideoPayload.image = {
      imageBytes: params.startFrame.base64,
      mimeType: params.startFrame.file.type,
    };
  }

  let operation = await ai.models.generateVideos(generateVideoPayload);

  while (!operation.done) {
    await new Promise((resolve) => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  if (operation?.response?.generatedVideos?.[0]?.video?.uri) {
    const videoObject = operation.response.generatedVideos[0].video;
    const url = decodeURIComponent(videoObject.uri);
    const res = await fetch(`${url}&key=${process.env.API_KEY}`);
    const videoBlob = await res.blob();
    const objectUrl = URL.createObjectURL(videoBlob);
    return {objectUrl, blob: videoBlob, uri: url, video: videoObject};
  } else {
    throw new Error('No videos generated.');
  }
};

