import {Video} from '@google/genai';
import React, {useCallback, useEffect, useState} from 'react';
import ApiKeyDialog from './components/ApiKeyDialog';
import LoadingIndicator from './components/LoadingIndicator';
import PromptForm from './components/PromptForm';
import VideoResult from './components/VideoResult';
import {generateVideo, generateImage, enhancePrompt} from './services/geminiService';
import {
  AppState,
  GenerateVideoParams,
  GenerationMode,
  Resolution,
  VideoFile,
  AspectRatio,
  VeoModel,
  ImageFile,
} from './types';
import { SparklesIcon, FilmIcon, Image as ImageIcon } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<ImageFile | null>(null);
  const [enhancedImagePrompt, setEnhancedImagePrompt] = useState("");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [showApiKeyDialog, setShowApiKeyDialog] = useState(false);
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE);

  useEffect(() => {
    const checkApiKey = async () => {
      if (window.aistudio) {
        try {
          if (!(await window.aistudio.hasSelectedApiKey())) {
            setShowApiKeyDialog(true);
          }
        } catch (error) {
          setShowApiKeyDialog(true);
        }
      }
    };
    checkApiKey();
  }, []);

  const handleStartWorkflow = async (initialPrompt: string, selectedAspectRatio: AspectRatio) => {
    setAspectRatio(selectedAspectRatio);
    setAppState(AppState.ENHANCING_IMAGE_PROMPT);
    try {
      const enhanced = await enhancePrompt(initialPrompt, 'artist');
      setEnhancedImagePrompt(enhanced);

      setAppState(AppState.GENERATING_IMAGE);
      const image = await generateImage(enhanced, selectedAspectRatio);
      setGeneratedImage(image);
      setAppState(AppState.IMAGE_READY);
    } catch (error: any) {
      setErrorMessage(error.message || "Failed to generate keyframe");
      setAppState(AppState.ERROR);
    }
  };

  const handleGenerateVideo = async (motionPrompt: string) => {
    if (!generatedImage) return;

    setAppState(AppState.ENHANCING_VIDEO_PROMPT);
    try {
      const enhancedVideoPrompt = await enhancePrompt(motionPrompt, 'director');

      setAppState(AppState.GENERATING_VIDEO);
      const params: GenerateVideoParams = {
        prompt: enhancedVideoPrompt,
        model: VeoModel.VEO_FAST,
        aspectRatio: aspectRatio,
        resolution: Resolution.P720,
        mode: GenerationMode.FRAMES_TO_VIDEO,
        startFrame: generatedImage
      };

      const {objectUrl} = await generateVideo(params);
      setVideoUrl(objectUrl);
      setAppState(AppState.SUCCESS);
    } catch (error: any) {
      setErrorMessage(error.message || "Video generation failed");
      setAppState(AppState.ERROR);
    }
  };

  const reset = () => {
    setAppState(AppState.IDLE);
    setVideoUrl(null);
    setGeneratedImage(null);
    setErrorMessage(null);
  };

  const StepIndicator = () => (
    <div className="flex justify-center items-center gap-4 mb-8">
      {[
        { label: 'Concept', state: AppState.IDLE, icon: SparklesIcon },
        { label: 'Keyframe', state: AppState.IMAGE_READY, icon: ImageIcon },
        { label: 'Motion', state: AppState.GENERATING_VIDEO, icon: FilmIcon }
      ].map((step, i) => {
        const isActive = appState === step.state || (i === 1 && appState > AppState.IMAGE_READY);
        const isDone = appState > step.state;
        return (
          <div key={i} className="flex items-center gap-2">
            <div className={`p-2 rounded-full border ${isActive ? 'bg-indigo-600 border-indigo-400 text-white' : 'border-gray-700 text-gray-500'}`}>
              <step.icon size={16} />
            </div>
            <span className={`text-xs font-medium uppercase tracking-widest ${isActive ? 'text-indigo-400' : 'text-gray-600'}`}>
              {step.label}
            </span>
            {i < 2 && <div className="w-8 h-px bg-gray-800" />}
          </div>
        );
      })}
    </div>
  );

  return (
    <div className="h-screen bg-[#050505] text-gray-200 flex flex-col font-sans overflow-hidden">
      {showApiKeyDialog && <ApiKeyDialog onContinue={() => setShowApiKeyDialog(false)} />}

      <header className="py-8 flex flex-col items-center px-8 z-10">
        <h1 className="text-4xl font-bold tracking-tighter mb-4 bg-gradient-to-b from-white to-gray-500 bg-clip-text text-transparent">
          VEO CINEMATIC STUDIO
        </h1>
        <StepIndicator />
      </header>

      <main className="w-full max-w-5xl mx-auto flex-grow flex flex-col p-4 overflow-y-auto custom-scrollbar">
        {appState === AppState.IDLE && (
          <div className="flex-grow flex flex-col items-center justify-center animate-in fade-in duration-700">
            <div className="text-center mb-8">
              <h2 className="text-2xl text-gray-400 mb-2">Start with your vision</h2>
              <p className="text-gray-600">Gemini will enhance your prompt to create a high-fidelity keyframe.</p>
            </div>
            <PromptForm 
              placeholder="e.g. A cyberpunk samurai overlooking a neon metropolis in the rain..."
              onSubmit={(p, ar) => handleStartWorkflow(p, ar)} 
            />
          </div>
        )}

        {(appState === AppState.ENHANCING_IMAGE_PROMPT || 
          appState === AppState.GENERATING_IMAGE || 
          appState === AppState.ENHANCING_VIDEO_PROMPT || 
          appState === AppState.GENERATING_VIDEO) && (
          <div className="flex-grow flex items-center justify-center">
            <LoadingIndicator state={appState} />
          </div>
        )}

        {appState === AppState.IMAGE_READY && generatedImage && (
          <div className="flex-grow flex flex-col items-center gap-8 animate-in zoom-in-95 duration-500">
            <div className="w-full max-w-3xl group relative">
              <div className="absolute -inset-1 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl blur opacity-20 group-hover:opacity-40 transition duration-1000"></div>
              <img 
                src={URL.createObjectURL(generatedImage.file)} 
                className="relative w-full rounded-xl shadow-2xl border border-gray-800"
                alt="Generated Keyframe"
              />
              <div className="absolute bottom-4 left-4 right-4 bg-black/60 backdrop-blur-md p-3 rounded-lg border border-white/10">
                <p className="text-xs text-indigo-300 font-mono line-clamp-2 italic">"{enhancedImagePrompt}"</p>
              </div>
            </div>

            <div className="w-full max-w-xl text-center">
              <h3 className="text-xl font-semibold mb-4 text-white">Action! Add motion to this scene.</h3>
              <PromptForm 
                placeholder="The camera pans slowly right as neon lights flicker..."
                buttonLabel="Roll Camera"
                hideAspectRatio
                onSubmit={(p) => handleGenerateVideo(p)}
              />
              <button onClick={reset} className="mt-4 text-sm text-gray-500 hover:text-gray-300 transition-colors">Start over</button>
            </div>
          </div>
        )}

        {appState === AppState.SUCCESS && videoUrl && (
          <VideoResult videoUrl={videoUrl} onNewVideo={reset} />
        )}

        {appState === AppState.ERROR && (
          <div className="flex-grow flex items-center justify-center">
             <div className="text-center bg-red-950/20 border border-red-500/50 p-12 rounded-2xl max-w-md">
                <h2 className="text-2xl font-bold text-red-400 mb-4">Production Halted</h2>
                <p className="text-red-300/80 mb-6">{errorMessage}</p>
                <button onClick={reset} className="px-8 py-3 bg-red-600 hover:bg-red-500 text-white rounded-xl transition-all font-bold">Try Again</button>
             </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

