import React, { useState } from 'react';
import { AspectRatio } from '../types';
import { Sparkles, ArrowRight, Layout, Maximize2 } from 'lucide-react';

interface PromptFormProps {
  onSubmit: (prompt: string, aspectRatio: AspectRatio) => void;
  placeholder?: string;
  buttonLabel?: string;
  hideAspectRatio?: boolean;
}

const PromptForm: React.FC<PromptFormProps> = ({ 
  onSubmit, 
  placeholder = "Describe your vision...", 
  buttonLabel = "Create Keyframe",
  hideAspectRatio = false
}) => {
  const [prompt, setPrompt] = useState("");
  const [aspectRatio, setAspectRatio] = useState<AspectRatio>(AspectRatio.LANDSCAPE);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (prompt.trim()) {
      onSubmit(prompt, aspectRatio);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="w-full max-w-2xl bg-[#111] border border-gray-800 rounded-3xl p-3 shadow-2xl focus-within:border-indigo-500/50 transition-all">
      <div className="flex flex-col gap-3">
        <textarea
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder={placeholder}
          className="w-full bg-transparent p-4 text-lg text-white placeholder-gray-600 focus:outline-none resize-none min-h-[100px]"
        />

        <div className="flex items-center justify-between border-t border-gray-800/50 pt-3 px-2">
          {!hideAspectRatio ? (
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => setAspectRatio(AspectRatio.LANDSCAPE)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm transition-all ${aspectRatio === AspectRatio.LANDSCAPE ? 'bg-indigo-600 text-white' : 'bg-gray-900 text-gray-500 hover:text-gray-300'}`}
              >
                <Layout size={14} /> 16:9
              </button>
              <button
                type="button"
                onClick={() => setAspectRatio(AspectRatio.PORTRAIT)}
                className={`flex items-center gap-2 px-4 py-2 rounded-xl text-sm transition-all ${aspectRatio === AspectRatio.PORTRAIT ? 'bg-indigo-600 text-white' : 'bg-gray-900 text-gray-500 hover:text-gray-300'}`}
              >
                <Maximize2 size={14} /> 9:16
              </button>
            </div>
          ) : <div />}

          <button
            type="submit"
            disabled={!prompt.trim()}
            className="flex items-center gap-2 px-6 py-2.5 bg-white text-black rounded-full font-bold hover:bg-indigo-400 hover:text-white transition-all disabled:opacity-30 disabled:cursor-not-allowed group"
          >
            {buttonLabel}
            <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>
    </form>
  );
};

export default PromptForm;

