import React, { useState, useEffect } from 'react';
import { AppState } from '../types';

interface Props {
  state: AppState;
}

const getMessages = (state: AppState) => {
  switch(state) {
    case AppState.ENHANCING_IMAGE_PROMPT: return ["AI Scriptwriter is drafting the concept...", "Enhancing visual details...", "Optimizing cinematic lighting parameters..."];
    case AppState.GENERATING_IMAGE: return ["Painting the keyframe...", "Generating high-fidelity textures...", "Finalizing composition..."];
    case AppState.ENHANCING_VIDEO_PROMPT: return ["Director is choreographing motion...", "Setting camera paths...", "Syncing visual continuity..."];
    case AppState.GENERATING_VIDEO: return ["Rolling cameras...", "Veo is rendering the sequence...", "Applying temporal consistency...", "This may take 1-2 minutes..."];
    default: return ["Working our magic..."];
  }
};

const LoadingIndicator: React.FC<Props> = ({ state }) => {
  const [messageIndex, setMessageIndex] = useState(0);
  const messages = getMessages(state);

  useEffect(() => {
    const interval = setInterval(() => {
      setMessageIndex((i) => (i + 1) % messages.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [messages]);

  return (
    <div className="flex flex-col items-center justify-center p-16">
      <div className="relative w-24 h-24 mb-12">
        <div className="absolute inset-0 rounded-full border-2 border-indigo-500/20"></div>
        <div className="absolute inset-0 rounded-full border-t-2 border-indigo-500 animate-spin"></div>
        <div className="absolute inset-4 rounded-full border-2 border-purple-500/10"></div>
        <div className="absolute inset-4 rounded-full border-b-2 border-purple-500 animate-spin-slow"></div>
      </div>
      <h2 className="text-2xl font-bold text-white mb-2 uppercase tracking-tighter">
        {state === AppState.GENERATING_VIDEO ? 'In Production' : 'Pre-Production'}
      </h2>
      <p className="text-indigo-400 font-mono text-sm animate-pulse">
        {messages[messageIndex]}
      </p>
      <style>{`
        @keyframes spin-slow {
          from { transform: rotate(0deg); }
          to { transform: rotate(-360deg); }
        }
        .animate-spin-slow {
          animation: spin-slow 3s linear infinite;
        }
      `}</style>
    </div>
  );
};

export default LoadingIndicator;

