import React, { useEffect, useState } from 'react';
import LoadingIndicator from './components/LoadingIndicator';
import PromptForm from './components/PromptForm';
import { generateImage, enhancePrompt } from './services/geminiService';
import {
  AppState,
  AspectRatio,
  ImageFile,
} from './types';
import { SparklesIcon, Image as ImageIcon, Download, RotateCcw } from 'lucide-react';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [generatedImage, setGeneratedImage] = useState<ImageFile | null>(null);
  const [enhancedImagePrompt, setEnhancedImagePrompt] = useState("");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const handleStartWorkflow = async (initialPrompt: string, selectedAspectRatio: AspectRatio) => {
    setAppState(AppState.ENHANCING_IMAGE_PROMPT);
    try {
      const enhanced = await enhancePrompt(initialPrompt);
      setEnhancedImagePrompt(enhanced);

      setAppState(AppState.GENERATING_IMAGE);
      const image = await generateImage(enhanced, selectedAspectRatio);
      setGeneratedImage(image);
      setAppState(AppState.SUCCESS);
    } catch (error: any) {
      setErrorMessage(error.message || "Failed to generate art");
      setAppState(AppState.ERROR);
    }
  };

  const reset = () => {
    setAppState(AppState.IDLE);
    setGeneratedImage(null);
    setErrorMessage(null);
    setEnhancedImagePrompt("");
  };

  const StepIndicator = () => (
    <div className="flex justify-center items-center gap-4 mb-8">
      {[
        { label: 'Concept', state: AppState.IDLE, icon: SparklesIcon },
        { label: 'Creation', state: AppState.SUCCESS, icon: ImageIcon },
      ].map((step, i) => {
        const isActive = appState === step.state || (i === 1 && appState === AppState.SUCCESS);
        return (
          <div key={i} className="flex items-center gap-2">
            <div className={`p-2 rounded-full border ${isActive ? 'bg-indigo-600 border-indigo-400 text-white' : 'border-gray-700 text-gray-500'}`}>
