import { GoogleGenAI, Modality } from '@google/genai';
import { AspectRatio, ImageFile, AgentConfig } from '../types';

// Agent 1: Orchestrateur - Analyse et améliore le prompt
export const orchestrate = async (prompt: string, config: AgentConfig): Promise<string> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const instruction = `PERSONA: ${config.orchestratorPersona}. Task: Transform the user's raw idea into a highly detailed cinematic visual prompt. Focus on mood, lighting, and technical specifications for an AI image generator. Return ONLY the enhanced prompt.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: { systemInstruction: instruction }
  });
  return response.text || prompt;
};

// Agent Image: Gemini 2.5 Flash Image
export const generateArt = async (prompt: string, aspectRatio: AspectRatio): Promise<ImageFile> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: prompt,
    config: {
      imageConfig: {
        aspectRatio: aspectRatio === AspectRatio.LANDSCAPE ? "16:9" : "9:16"
      }
    }
  });

  const part = response.candidates[0].content.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("Image agent failed to create asset");

  const base64 = part.inlineData.data;
  const byteCharacters = atob(base64);
  const byteNumbers = new Array(byteCharacters.length);
  for (let i = 0; i < byteCharacters.length; i++) {
    byteNumbers[i] = byteCharacters.charCodeAt(i);
  }
  const byteArray = new Uint8Array(byteNumbers);
  const blob = new Blob([byteArray], {type: 'image/png'});
  const file = new File([blob], "prod_asset.png", {type: 'image/png'});

  return { file, base64 };
};

// Agent 2: Marketer - Analyse l'image et crée le message publicitaire
export const marketAnalysis = async (image: ImageFile, prompt: string, config: AgentConfig): Promise<string> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const instruction = `PERSONA: ${config.marketerPersona}. Task: Analyze the image and original concept. Create a powerful marketing headline and a 3-sentence advertising copy that sells this visual as a premium brand.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      { text: `Context: ${prompt}` },
      { inlineData: { data: image.base64, mimeType: 'image/png' } }
    ],
    config: { systemInstruction: instruction }
  });
  return response.text || "Marketing content generation failed.";
};

// Agent 3: Director - Crée le script et génère la vidéo Veo
export const generateCampaignVideo = async (
  image: ImageFile, 
  marketingCopy: string, 
  aspectRatio: AspectRatio
): Promise<{url: string; video: any}> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

  // Scripting step with Gemini Pro
  const scriptResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `IMAGE ASSET READY. MARKETING COPY: ${marketingCopy}. Create a technical motion prompt for Veo 3.1 that brings this scene to life as a high-end commercial. Describe dynamic camera moves.`,
  });

  const motionPrompt = scriptResponse.text || "Cinematic commercial with slow motion and atmospheric lighting.";

  // Video Generation step with Veo
  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: motionPrompt,
    image: {
      imageBytes: image.base64,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: aspectRatio,
    }
  });

  while (!operation.done) {
    await new Promise((resolve) => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  const videoObject = operation.response?.generatedVideos?.[0]?.video;
  if (!videoObject?.uri) throw new Error('Video production failed.');

  const res = await fetch(`${videoObject.uri}&key=${process.env.API_KEY}`);
  const blob = await res.blob();
  return { url: URL.createObjectURL(blob), video: videoObject };
};

