import { GoogleGenAI } from '@google/genai';
import { AspectRatio, ImageFile, AgentConfig, SocialPlatform } from '../types';

// Agent 1: Orchestrateur - Adapté à la plateforme
export const orchestrate = async (prompt: string, config: AgentConfig, platform: SocialPlatform): Promise<string> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const instruction = `PERSONA: ${config.orchestratorPersona}. 
  TARGET PLATFORM: ${platform}.
  Task: Transform the user's idea into a detailed cinematic visual prompt. 
  If platform is TikTok/Instagram, focus on vertical-first compositions, vibrant colors, and fast-paced visual hooks.
  If LinkedIn/X, focus on professional, sleek, and minimalist high-end aesthetics.
  Return ONLY the enhanced prompt.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: { systemInstruction: instruction }
  });
  return response.text || prompt;
};

// Agent Image: Gemini 2.5 Flash Image
export const generateArt = async (prompt: string, aspectRatio: AspectRatio): Promise<ImageFile> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: prompt,
    config: {
      imageConfig: {
        aspectRatio: aspectRatio === AspectRatio.LANDSCAPE ? "16:9" : "9:16"
      }
    }
  });

  const part = response.candidates[0].content.parts.find(p => p.inlineData);
  if (!part?.inlineData) throw new Error("L'agent Artiste n'a pas pu créer le visuel.");

  const base64 = part.inlineData.data;
  const byteCharacters = atob(base64);
  const byteNumbers = new Array(byteCharacters.length);
  for (let i = 0; i < byteCharacters.length; i++) {
    byteNumbers[i] = byteCharacters.charCodeAt(i);
  }
  const byteArray = new Uint8Array(byteNumbers);
  const blob = new Blob([byteArray], {type: 'image/png'});
  const file = new File([blob], "campaign_asset.png", {type: 'image/png'});

  return { file, base64 };
};

// Agent 2: Marketer - Adapté à la plateforme (hashtags, ton)
export const marketAnalysis = async (image: ImageFile, prompt: string, config: AgentConfig, platform: SocialPlatform): Promise<string> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});
  const instruction = `PERSONA: ${config.marketerPersona}. 
  TARGET PLATFORM: ${platform}.
  Task: Analyze the image. Create a marketing headline and copy tailored for ${platform}.
  - TikTok/Instagram: Use emojis, trendy language, and relevant hashtags. Keep it punchy.
  - LinkedIn: Professional, value-driven, structured.
  - YouTube: Click-worthy headline (Thumbnail style) and description.
  Return the copy with platform-specific formatting.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: [
      { text: `Context: ${prompt}` },
      { inlineData: { data: image.base64, mimeType: 'image/png' } }
    ],
    config: { systemInstruction: instruction }
  });
  return response.text || "Échec de la génération marketing.";
};

// Agent 3: Director - Adapté à la plateforme (mouvements caméra)
export const generateCampaignVideo = async (
  image: ImageFile, 
  marketingCopy: string, 
  aspectRatio: AspectRatio,
  platform: SocialPlatform
): Promise<{url: string; video: any}> => {
  const ai = new GoogleGenAI({apiKey: process.env.API_KEY});

  const scriptResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `IMAGE READY. PLATFORM: ${platform}. COPY: ${marketingCopy}. 
    Create a motion prompt for Veo 3.1. 
    If ${platform} is TikTok, suggest fast zooms or trendy transitions. 
    If YouTube, suggest smooth cinematic pans.`,
  });

  const motionPrompt = scriptResponse.text || "Cinematic commercial movement.";

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: motionPrompt,
    image: {
      imageBytes: image.base64,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: aspectRatio,
    }
  });

  while (!operation.done) {
    await new Promise((resolve) => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  const videoObject = operation.response?.generatedVideos?.[0]?.video;
  if (!videoObject?.uri) throw new Error('Échec de la production vidéo.');

  const res = await fetch(`${videoObject.uri}&key=${process.env.API_KEY}`);
  const blob = await res.blob();
  return { url: URL.createObjectURL(blob), video: videoObject };
};

