export enum AspectRatio {
  LANDSCAPE = '16:9',
  PORTRAIT = '9:16',
}

export enum SocialPlatform {
  TIKTOK = 'TikTok',
  INSTAGRAM = 'Instagram',
  YOUTUBE_SHORTS = 'YouTube Shorts',
  YOUTUBE = 'YouTube',
  FACEBOOK = 'Facebook',
